+              frame_properties[PANGO_SENSOR_TEMPERATURE_C] = json::value(val);
+          } else {
+              pango_print_error("DeviceTemperatureCelsius %f fail\n", val);
+          }
+      }
+      return true;
+  } else {
+      return false;
+  }
+
